using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    [TestClass]
    public sealed class CreateOrder
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void WithValidItems_ReturnsOrderWithCorrectTotal()
        {
            var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 5.50m, 3));

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual("cust-1", order.CustomerId);
            Assert.AreEqual(36.50m, order.Total);
            Assert.AreEqual(2, order.Items.Count);
            Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        }

        [TestMethod]
        public void WithValidItems_SetsCreatedAtToUtcNow()
        {
            var before = DateTime.UtcNow;
            var order = _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
            var after = DateTime.UtcNow;

            Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
        }

        [TestMethod]
        public void WithSingleItem_CalculatesTotalCorrectly()
        {
            var order = _sut.CreateOrder("cust-1", CreateItems(("Item", 7.25m, 4)));

            Assert.AreEqual(29.00m, order.Total);
        }

        [TestMethod]
        public void WithNullCustomerId_ThrowsArgumentNullException()
        {
            var items = CreateItems(("Widget", 10.00m, 1));

            Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        }

        [TestMethod]
        public void WithNullItems_ThrowsArgumentNullException()
        {
            Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
        }

        [TestMethod]
        public void WithEmptyItems_ThrowsInvalidOperationException()
        {
            Assert.ThrowsExactly<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
        }

        [TestMethod]
        public void StoresOrderForRetrieval()
        {
            var order = _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

            var retrieved = _sut.GetOrder(order.Id);

            Assert.AreEqual(order.Id, retrieved?.Id);
        }

        private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
            items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();
    }

    [TestClass]
    public sealed class GetOrder
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void WithExistingId_ReturnsOrder()
        {
            var created = _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

            var result = _sut.GetOrder(created.Id);

            Assert.IsNotNull(result);
            Assert.AreEqual(created.Id, result.Id);
        }

        [TestMethod]
        public void WithNonExistentId_ReturnsNull()
        {
            var result = _sut.GetOrder("does-not-exist");

            Assert.IsNull(result);
        }

        private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
            items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();
    }

    [TestClass]
    public sealed class GetOrdersByCustomer
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void WithMultipleOrders_ReturnsOnlyMatchingCustomer()
        {
            _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
            _sut.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));
            _sut.CreateOrder("cust-1", CreateItems(("C", 3m, 1)));

            var results = _sut.GetOrdersByCustomer("cust-1");

            Assert.AreEqual(2, results.Count);
            Assert.IsTrue(results.All(o => o.CustomerId == "cust-1"));
        }

        [TestMethod]
        public void WithNoOrders_ReturnsEmptyList()
        {
            var results = _sut.GetOrdersByCustomer("cust-999");

            Assert.AreEqual(0, results.Count);
        }

        private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
            items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();
    }
}

